  code += `        images: ['[IMG:illustration|${title}\u751f\u6d3b\u5e94\u7528|400x300|cartoon|png|\u751f\u6d3b\u5e94\u7528]','[IMG:illustration|${title}\u5e94\u7528\u9898|300x250|cartoon|png|\u5e94\u7528\u9898]'],\n`;
  code += `        content: [\n`;
